// /frontend/src/components/Radar.jsx
import React, { useEffect, useRef, useState } from "react";
import L from "leaflet";
import "leaflet/dist/leaflet.css";

const METADATA_URL = "https://api.rainviewer.com/public/weather-maps.json";
const LATEST_ONLY = true;         // show only latest tile for instant load
const LOAD_TIMEOUT_MS = 3500;     // fail fast if CDN is slow

export default function Radar() {
  const mapRef = useRef(null);
  const radarLayerRef = useRef(null);
  const [loading, setLoading] = useState(true);
  const [errorText, setErrorText] = useState("");

  // init map
  useEffect(() => {
    if (mapRef.current) return;
    const map = L.map("radar-map", {
      zoomControl: false,
      attributionControl: false,
      preferCanvas: true,
    }).setView([33.749, -84.388], 6);
    L.tileLayer(
      "https://{s}.tile.basemaps.cartocdn.com/dark_all/{z}/{x}/{y}{r}.png",
      { subdomains: "abcd", maxZoom: 18, opacity: 0.9 }
    ).addTo(map);
    mapRef.current = map;

    // If container resizes after render, make sure tiles snap in
    setTimeout(() => map.invalidateSize(), 0);
  }, []);

  // load radar (latest only for speed)
  useEffect(() => {
    let alive = true;
    let timeoutId;

    (async () => {
      try {
        // Hard timeout guard
        timeoutId = setTimeout(() => {
          if (!alive) return;
          setLoading(false);
          setErrorText("Radar is slow right now. Showing base map only.");
        }, LOAD_TIMEOUT_MS);

        const meta = await fetch(METADATA_URL).then((r) => r.json());
        if (!alive) return;

        const host = meta?.host || "";
        const frames = [...(meta?.radar?.past || []), ...(meta?.radar?.nowcast || [])];
        if (!host || frames.length === 0) {
          clearTimeout(timeoutId);
          setLoading(false);
          setErrorText("No radar frames available.");
          return;
        }

        const keep = LATEST_ONLY ? frames.slice(-1) : frames.slice(-6);
        let idx = keep.length - 1;

        const map = mapRef.current;
        const showFrame = (i) => {
          const ts = keep[i]?.time;
          if (!ts) return;
          const url = `${host}/v2/radar/${ts}/256/{z}/{x}/{y}.png`;
          // swap fast
          if (radarLayerRef.current) map.removeLayer(radarLayerRef.current);
          const layer = L.tileLayer(url, {
            opacity: 0.85,
            zIndex: 500,
            crossOrigin: true,
          })
            .on("load", () => {
              clearTimeout(timeoutId);
              setLoading(false);
              setErrorText("");
            })
            .on("tileerror", () => {
              // If a tile fails, don't block the whole layer; just let the timeout handle it.
            })
            .addTo(map);
          radarLayerRef.current = layer;
        };

        showFrame(idx);

        if (!LATEST_ONLY) {
          const id = setInterval(() => {
            idx = (idx + 1) % keep.length;
            showFrame(idx);
          }, 800);
          return () => clearInterval(id);
        }
      } catch (e) {
        console.error("Radar load error:", e);
        setErrorText("Radar failed to load.");
        setLoading(false);
      } finally {
        clearTimeout(timeoutId);
      }
    })();

    return () => {
      alive = false;
      clearTimeout(timeoutId);
    };
  }, []);

  return (
    <div className="relative rounded-2xl overflow-hidden backdrop-blur-xl bg-black/40 ring-1 ring-white/10">
      <div className="flex items-center justify-between px-3 py-2">
        <div className="text-sm opacity-80">Radar</div>
      </div>

      <div id="radar-map" style={{ height: 320, width: "100%" }} />

      {loading && (
        <div className="absolute inset-0 grid place-items-center">
          <div className="animate-spin h-6 w-6 rounded-full border-2 border-white/30 border-t-white" />
        </div>
      )}

      {!!errorText && !loading && (
        <div className="absolute bottom-2 left-2 right-2 text-xs px-2 py-1 rounded bg-black/70 ring-1 ring-white/10">
          {errorText}
        </div>
      )}

      <div className="absolute bottom-3 left-3 text-[11px] rounded bg-black/60 px-2 py-1 ring-1 ring-white/10">
        <div className="font-medium mb-1">Precip Intensity</div>
        <div className="flex items-center gap-2">
          <span className="inline-block h-2 w-6 bg-yellow-400" /> Moderate
          <span className="inline-block h-2 w-6 bg-red-500" /> Heavy (red)
          <span className="inline-block h-2 w-6 bg-blue-400" /> Snow (blue)
        </div>
      </div>
    </div>
  );
}
